419	/// Close a regular file via `fclose`. C: `io_fclose`.
420	///
421	/// TODO(port): flush + drop `Box<dyn LuaFileOps>`, map io::Error to file_result.
422	fn io_fclose(state: &mut LuaState) -> Result<usize, LuaError> {
423	    // C: return luaL_fileresult(L, (fclose(p->f) == 0), NULL);
424	    let p = get_lstream(state)?;
425	    // TODO(port): actually flush then drop p.file, capture any error
426	    let _closed = p.file.take();
427	    state.push(LuaValue::Bool(true));
428	    Ok(1)
429	}
