431	/// Close a popen process pipe. C: `io_pclose`.
432	///
433	/// TODO(port): std::process::Child — popen not yet implemented.
434	fn io_pclose(state: &mut LuaState) -> Result<usize, LuaError> {
435	    // C: return luaL_execresult(L, l_pclose(L, p->f));
436	    let p = get_lstream(state)?;
437	    let _closed = p.file.take();
438	    // TODO(port): wait on the child process and forward its exit code
439	    exec_result(state, 0)
440	}
