453	/// Invoke the stream's close function and mark it closed. C: `aux_close`.
454	fn aux_close(state: &mut LuaState) -> Result<usize, LuaError> {
455	    // C: volatile lua_CFunction cf = p->closef; p->closef = NULL; return (*cf)(L);
456	    let p = get_lstream(state)?;
457	    let cf = p.close_fn.take().ok_or_else(|| {
458	        LuaError::runtime(format_args!("attempt to close an already-closed file"))
459	    })?;
460	    cf(state)
461	}
