465	/// `io.type(x)` — return `"file"`, `"closed file"`, or `false`. C: `io_type`.
466	pub fn io_type(state: &mut LuaState) -> Result<usize, LuaError> {
467	    // C: luaL_checkany(L, 1);
468	    state.check_arg_any(1)?;
469	    // C: p = (LStream *)luaL_testudata(L, 1, LUA_FILEHANDLE);
470	    // C: if (p == NULL) luaL_pushfail(L);
471	    // C: else if (isclosed(p)) lua_pushliteral(L, "closed file");
472	    // C: else lua_pushliteral(L, "file");
473	    let maybe_userdata = state.test_arg_userdata(1, LUA_FILE_HANDLE);
474	    if maybe_userdata.is_none() {
475	        state.push(LuaValue::Bool(false));
476	    } else {
477	        // TODO(port): typed cast to check LStream::is_closed()
478	        let is_closed: bool = todo!("TODO(port): typed userdata access for io_type");
479	        if is_closed {
480	            state.push_string(b"closed file");
481	        } else {
482	            state.push_string(b"file");
483	        }
484	    }
485	    Ok(1)
